 const _20241212CherGensDadobe = "{\"parsed\":{\"_path\":\"/fr/20241212-cher-gens-dadobe\",\"_dir\":\"fr\",\"_draft\":false,\"_partial\":false,\"_locale\":\"\",\"title\":\"Pourquoi tant de haine envers Adobe ? (Parce qu'elle est méritée.)\",\"description\":\"Découvrez pourquoi Adobe suscite tant de critiques : pratiques commerciales douteuses, service client défaillant et frais cachés. Un témoignage personnel sur les frustrations liées à cette entreprise incontournable du design.\",\"image\":\"/images/articles/adobe.webp\",\"createdAt\":\"2024-12-12\",\"id\":\"2024-12-12T00:00:00.000Z\",\"keywords\":\"Adobe, critique Adobe, Affinity Designer, abonnement Adobe, frais cachés Adobe, service client Adobe, alternatives Adobe, pratiques commerciales Adobe, procès Adobe, FTC Adobe\",\"summary\":\"Un témoignage personnel sur les frustrations liées à Adobe : service client défaillant, abonnements forcés et interfaces trompeuses. L'article explique pourquoi les critiques envers Adobe sont justifiées, mentionne les poursuites judiciaires en cours et suggère des alternatives comme Affinity.\",\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"h1\",\"props\":{\"id\":\"pourquoi-tant-de-haine-envers-adobe-parce-quelle-est-méritée\"},\"children\":[{\"type\":\"text\",\"value\":\"Pourquoi tant de haine envers Adobe ? Parce qu'elle est méritée.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Bien qu'Affinity Designer soit une belle alternative, dans un cadre professionnel, je n'ai pas d'autre choix que d'utiliser Adobe. En effet, la plupart des designs que je dois transformer en code et en site web sont réalisés sur Adobe, et je ne maîtrise pas encore suffisamment Affinity Photo 2 pour éditer avec confiance les fichiers RAW issus de ma caméra Theta Z1.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Je dois donc utiliser Adobe... mais parfois au détriment de ma santé mentale, sans parler du prix. Je conviens que mon jugement est peut-être un peu exagéré, mais je suis profondément déçu de ne pas avoir d'alternative à Adobe.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Or, ce matin, ma frustration a atteint un point culminant. Je HAIS Adobe, et je me suis juré de me plonger à fond dans la suite Affinity, loin des tracas d'Adobe. Laissez-moi vous expliquer.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Tout a commencé un vendredi 13 décembre, lorsque j'ai voulu mettre à jour mes moyens de paiement sur un compte Adobe. Première surprise d'une série rendant ce début de journée particulièrement difficile :\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Impossible de le faire soi-même, car la commande de menu permettant, comme partout ailleurs, de le faire n'existe pas. Il faut obligatoirement passer par leur service client, ce qui est tout sauf rapide et simple.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Après avoir cliqué sur le bouton \\\"aide\\\", vous serez confronté à une intelligence artificielle qui semble conçue soit pour tester votre patience, soit pour vous faire abandonner.\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Par malchance pour eux, je suis du genre patient et déterminé quand il s'agit de certaines entreprises (incluant, mais non limitées à ma banque, Apple et Adobe). Et gentil également, donc voici un tuto en 3 étapes pour échapper à l'IA et atteindre un humain :\"}]},{\"type\":\"element\",\"tag\":\"ol\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Exigez un humain\"}]},{\"type\":\"text\",\"value\":\" : Insistez, répétez \\\"je veux parler à un humain\\\" jusqu'à ce que l'IA cède (tout en restant poli).\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Choisissez une option, peu importe laquelle\"}]},{\"type\":\"text\",\"value\":\" : Pas besoin d'être précis, l'important est d'avancer.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Persistez\"}]},{\"type\":\"text\",\"value\":\" : Continuez jusqu'à ce qu'un agent humain daigne enfin intervenir.\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Après beaucoup d'efforts, j'ai réussi à parler à un conseiller. Non sans réticence, il a accédé à ma demande. Tout semblait enfin réglé, jusqu'à ce que je découvre, 30 minutes plus tard, un abonnement à Adobe Express ajouté à mon compte.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Je n'utilise même pas ce service et je ne souhaite pas payer plus que nécessaire. Qui plus est, Canva est bien meilleur dans le domaine des éditeurs tout-en-un et faciles à prendre en main.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Une nouvelle bataille avec le service client s'en est suivie : \\\"Je ne veux pas de Adobe Express, je ne l'utilise pas et je ne veux pas payer pour ça.\\\" Après être passé par deux conseillers clients, j'ai annulé cet abonnement non sollicité. Mais cette expérience a laissé un goût amer : Adobe, par ses pratiques abusives, suscite des critiques largement méritées, ainsi que toute la haine du monde. Sur internet, dans la vie et les tribunes.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Car oui, Adobe fait face à plusieurs procès pour des pratiques commerciales douteuses :\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Frais de résiliation cachés\"}]},{\"type\":\"text\",\"value\":\" : Le ministère américain de la Justice poursuit Adobe pour avoir dissimulé des frais d'annulation pouvant atteindre plusieurs centaines de dollars. Ces frais concernent les abonnements annuels payés mensuellement.\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Interfaces trompeuses\"}]},{\"type\":\"text\",\"value\":\" : La Federal Trade Commission (FTC) accuse Adobe de concevoir des interfaces qui poussent les utilisateurs à s'abonner sans divulguer clairement les conditions. Annuler devient alors un parcours semé d'embûches.\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Ces histoires révèlent une stratégie bien rodée pour rendre l'expérience utilisateur délibérément frustrante.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"En conclusion : Arrêtez d'utiliser leurs services, si possible. Ou optez pour un abonnement mensuel, sans engagement (i.e Affinity).\"}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[]}},\"_type\":\"markdown\",\"_id\":\"content:fr:20241212-cher-gens-dadobe.md\",\"_source\":\"content\",\"_file\":\"fr/20241212-cher-gens-dadobe.md\",\"_stem\":\"fr/20241212-cher-gens-dadobe\",\"_extension\":\"md\",\"sitemap\":{\"loc\":\"/fr/20241212-cher-gens-dadobe\"}},\"hash\":\"xh66U9QPmb\"}";

export { _20241212CherGensDadobe as default };
